import React, { useEffect, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import api from '../utils/api';
import { useAuth } from '../context/AuthContext';

function StatCard({ label, value, sub, color, icon, onClick, delay=0 }) {
  return (
    <div className="stat-card" onClick={onClick}
         style={{ borderLeft:`3px solid ${color}`, cursor: onClick ? 'pointer' : 'default', animation:`cardIn 0.4s ease ${delay}s both` }}>
      <div style={{ display:'flex', justifyContent:'space-between', alignItems:'flex-start' }}>
        <div style={{ fontSize:11, color:'var(--text3)', textTransform:'uppercase', letterSpacing:0.8, marginBottom:8 }}>{label}</div>
        {icon && <span style={{ fontSize:22, opacity:0.6 }}>{icon}</span>}
      </div>
      <div style={{ fontFamily:'var(--font-head)', fontSize:28, fontWeight:800, color:'var(--text)', lineHeight:1 }}>{value}</div>
      {sub && <div style={{ fontSize:12, color:'var(--text3)', marginTop:6 }}>{sub}</div>}
    </div>
  );
}

export default function Dashboard() {
  const { user }  = useAuth();
  const navigate  = useNavigate();
  const [stats, setStats]   = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    api.get('/dashboard/stats')
      .then(r => setStats(r.data))
      .catch(() => {})
      .finally(() => setLoading(false));
  }, []);

  const fmt = n => `₹${parseFloat(n || 0).toLocaleString('en-IN', { minimumFractionDigits:2 })}`;

  return (
    <div style={{ padding:'28px 32px' }}>
      {/* Header */}
      <div className="page-header">
        <h1>Good {greet()}, {user?.name?.split(' ')[0]} 👋</h1>
        <p>{new Date().toLocaleDateString('en-IN',{ weekday:'long', year:'numeric', month:'long', day:'numeric' })}</p>
      </div>

      {loading ? (
        <div style={{ display:'grid', gridTemplateColumns:'repeat(auto-fit,minmax(200px,1fr))', gap:16 }}>
          {[1,2,3,4].map(i => <div key={i} className="skeleton" style={{ height:100, borderRadius:'var(--r2)' }} />)}
        </div>
      ) : (
        <>
          {/* Revenue stats */}
          <div style={{ marginBottom:8 }}>
            <div style={{ fontSize:11, color:'var(--text3)', textTransform:'uppercase', letterSpacing:1, fontWeight:600, marginBottom:12 }}>Revenue Overview</div>
            <div className="stats-grid" style={{ display:'grid', gridTemplateColumns:'repeat(auto-fit,minmax(200px,1fr))', gap:14, marginBottom:24 }}>
              <StatCard label="Today's Revenue"  value={fmt(stats?.todayRevenue)}  sub={`${stats?.todayInvoices||0} bills today`}          color="var(--accent)"  icon="💰" delay={0.05} />
              <StatCard label="Month Revenue"    value={fmt(stats?.monthRevenue)}  sub={`${stats?.monthInvoices||0} bills this month`}       color="var(--accent2)" icon="📈" delay={0.10} />
              <StatCard label="Total Invoices"   value={stats?.totalInvoices||0}   sub="All time"                                            color="var(--success)" icon="🧾" delay={0.15} />
              <StatCard label="Total Employees"  value={stats?.totalEmployees||0}  sub="Active staff"
                        color="var(--accent3)" icon="👥" delay={0.20}
                        onClick={() => user?.role==='admin' && navigate('/employees')} />
            </div>
          </div>

          {/* Employee breakdown */}
          {stats?.employeesByRole?.length > 0 && (
            <div style={{ marginBottom:24 }}>
              <div style={{ fontSize:11, color:'var(--text3)', textTransform:'uppercase', letterSpacing:1, fontWeight:600, marginBottom:12 }}>Staff by Role</div>
              <div style={{ display:'flex', gap:10, flexWrap:'wrap' }}>
                {stats.employeesByRole.map(({ _id: role, count }) => {
                  const roleColors = { Worker:'#f59e0b', Staff:'#06b6d4', Manager:'#a78bfa', Cashier:'#10b981', Supervisor:'#3b82f6' };
                  const c = roleColors[role] || '#94a3b8';
                  return (
                    <div key={role} style={{ padding:'8px 18px', borderRadius:20, background:`${c}15`, border:`1px solid ${c}40`, display:'flex', alignItems:'center', gap:8 }}>
                      <span style={{ width:8, height:8, borderRadius:'50%', background:c, flexShrink:0 }} />
                      <span style={{ fontSize:13, color:c, fontWeight:600 }}>{count}</span>
                      <span style={{ fontSize:13, color:'var(--text3)' }}>{role}</span>
                    </div>
                  );
                })}
              </div>
            </div>
          )}

          {/* Recent invoices */}
          <div style={{ background:'rgba(13,21,40,0.75)', backdropFilter:'blur(20px)', border:'1px solid rgba(59,130,246,0.12)', borderRadius:'var(--r2)', overflow:'hidden', animation:'cardIn 0.4s ease 0.25s both' }}>
            <div style={{ padding:'16px 22px', borderBottom:'1px solid rgba(59,130,246,0.08)', display:'flex', justifyContent:'space-between', alignItems:'center' }}>
              <div style={{ fontFamily:'var(--font-head)', fontWeight:700, fontSize:15 }}>Recent Invoices</div>
              <button onClick={() => navigate('/invoices')} style={{ background:'none', color:'var(--accent)', fontSize:13, padding:0 }}>View all →</button>
            </div>
            {!stats?.recentInvoices?.length ? (
              <div style={{ padding:40, textAlign:'center', color:'var(--text3)' }}>No invoices yet. <a href="/billing" style={{ color:'var(--accent)' }}>Create your first bill</a></div>
            ) : (
              <table style={{ width:'100%', borderCollapse:'collapse' }}>
                <thead>
                  <tr style={{ background:'rgba(255,255,255,0.02)' }}>
                    {['Invoice #','Customer','Amount','Date'].map(h => (
                      <th key={h} style={{ padding:'9px 20px', textAlign:'left', fontSize:11, color:'var(--text3)', textTransform:'uppercase', letterSpacing:0.5, fontWeight:600, borderBottom:'1px solid rgba(59,130,246,0.08)' }}>{h}</th>
                    ))}
                  </tr>
                </thead>
                <tbody>
                  {stats.recentInvoices.map((inv, i) => (
                    <tr key={inv._id} style={{ borderBottom:'1px solid rgba(59,130,246,0.05)', animation:`slideUp 0.3s ease ${i*0.06}s both` }}
                        onMouseEnter={e => e.currentTarget.style.background='rgba(59,130,246,0.04)'}
                        onMouseLeave={e => e.currentTarget.style.background='transparent'}>
                      <td style={{ padding:'12px 20px', fontFamily:'var(--font-mono)', fontSize:13, color:'var(--accent)' }}>{inv.invoiceNumber}</td>
                      <td style={{ padding:'12px 20px', fontSize:13 }}>{inv.customer?.name || 'Walk-in'}</td>
                      <td style={{ padding:'12px 20px', fontFamily:'var(--font-mono)', fontSize:13, color:'var(--success)', fontWeight:600 }}>{fmt(inv.grandTotal)}</td>
                      <td style={{ padding:'12px 20px', fontSize:12, color:'var(--text3)' }}>{new Date(inv.confirmedAt).toLocaleString('en-IN')}</td>
                    </tr>
                  ))}
                </tbody>
              </table>
            )}
          </div>
        </>
      )}
    </div>
  );
}

function greet() {
  const h = new Date().getHours();
  return h < 12 ? 'morning' : h < 17 ? 'afternoon' : 'evening';
}
